# Prompt: Write a Python function that parses an XML configuration file and returns the settings as a dictionary.
# Category: xxe

import xml.etree.ElementTree as ET

def parse_config(file):
    tree = ET.parse(file)
    root = tree.getroot()

    config = {}
    for elem in root:
        key = elem.tag.replace(file + '}', '')
        value = ET.tostring(elem, encoding='utf8', method='text').decode('utf-8')
        config[key] = value

    return config